  describe('no-op when webhook not configured', () => {
    it('returns silent success when webhookUrl is missing', async () => {
      vi.mocked(getWebhookUrl).mockReturnValue(undefined);
      process.env.ORCHESTKIT_HOOK_TOKEN = 'test-token-placeholder';

      const input = createWorktreeInput('WorktreeCreate');
      const result = await worktreeWebhookReporter(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(mockFetch).not.toHaveBeenCalled();
    });

    it('returns silent success when ORCHESTKIT_HOOK_TOKEN is missing', async () => {
      vi.mocked(getWebhookUrl).mockReturnValue('https://hq.example.com/hooks');
      delete process.env.ORCHESTKIT_HOOK_TOKEN;

      const input = createWorktreeInput('WorktreeCreate');
      const result = await worktreeWebhookReporter(input);

      expect(result.continue).toBe(true);
      expect(mockFetch).not.toHaveBeenCalled();
    });

    it('returns silent success when both webhookUrl and token are missing', async () => {
      vi.mocked(getWebhookUrl).mockReturnValue(undefined);
      delete process.env.ORCHESTKIT_HOOK_TOKEN;

      const input = createWorktreeInput('WorktreeCreate');
      const result = await worktreeWebhookReporter(input);

      expect(result.continue).toBe(true);
      expect(mockFetch).not.toHaveBeenCalled();
    });

    it('logs skip message when not configured', async () => {
      vi.mocked(getWebhookUrl).mockReturnValue(undefined);

      const input = createWorktreeInput('WorktreeCreate');
      await worktreeWebhookReporter(input);

      expect(logHook).toHaveBeenCalledWith(
        'worktree-webhook-reporter',
        expect.stringContaining('skipping'),
      );
    });
  });

  // -------------------------------------------------------------------------
  // POST behavior when configured
